fn test_silhouette_well_separated() {
        let data: Vec<Vec<f32>> = vec![
            vec![0.0, 0.0],
            vec![0.1, 0.0],
            vec![0.0, 0.1],
            vec![10.0, 10.0],
            vec![10.1, 10.0],
            vec![10.0, 10.1],
        ];
        let assignments = vec![0, 0, 0, 1, 1, 1];
        let score = silhouette_score(&data, &assignments, 2);
        assert!(
            score > 0.9,
            "Well-separated clusters should have silhouette > 0.9, got {score}"
        );
    }
